    pub fn parse_market(&self, mut market: Value) -> Value {
        //
        //    {
        //        "instrument": "BTC_USDT_Perp",
        //        "instrument_hash": "0x030501",
        //        "base": "BTC",
        //        "quote": "USDT",
        //        "kind": "PERPETUAL",
        //        "venues": [
        //            "ORDERBOOK",
        //            "RFQ"
        //        ],
        //        "settlement_period": "PERPETUAL",
        //        "base_decimals": 9,
        //        "quote_decimals": 6,
        //        "tick_size": "0.1",
        //        "min_size": "0.001",
        //        "create_time": "1768040726362828205",
        //        "max_position_size": "1000.0",
        //        "funding_interval_hours": 8,
        //        "adjusted_funding_rate_cap": "0.3",
        //        "adjusted_funding_rate_floor": "-0.3",
        //        "min_notional": "100.0"
        //    }
        //
        let mut marketId: Value = self.safe_string_k(market.clone(), "instrument", &[]);
        let mut baseId: Value = self.safe_string_k(market.clone(), "base", &[]);
        let mut quoteId: Value = self.safe_string_k(market.clone(), "quote", &[]);
        let mut settleId: Value = quoteId.clone();
        let mut base: Value = self.safe_currency_code(baseId.clone(), &[]);
        let mut quote: Value = self.safe_currency_code(quoteId.clone(), &[]);
        let mut settle: Value = self.safe_currency_code(settleId.clone(), &[]);
        let mut symbol: Value = add(&add(&add(&add(&base, &Value::Str("/".to_string())), &quote), &Value::Str(":".to_string())), &settle);
        let mut type_var: Value = Value::Null;
        let mut typeRaw: Value = self.safe_string_k(market.clone(), "kind", &[]);
        if is_equal(&typeRaw, &Value::Str("PERPETUAL".to_string())) {
            type_var = Value::Str("swap".to_string());
        }
        let mut isSpot: Value = Value::Bool(is_equal(&type_var, &Value::Str("spot".to_string())));
        let mut isSwap: Value = Value::Bool(is_equal(&type_var, &Value::Str("swap".to_string())));
        let mut isFuture: Value = Value::Bool(is_equal(&type_var, &Value::Str("future".to_string())));
        let mut isContract: Value = Value::Bool(is_true(&isSwap) || is_true(&isFuture));
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), marketId.clone());
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("base".to_string(), base.clone());
        m.insert("quote".to_string(), quote.clone());
        m.insert("settle".to_string(), settle.clone());
        m.insert("baseId".to_string(), baseId.clone());
        m.insert("quoteId".to_string(), quoteId.clone());
        m.insert("settleId".to_string(), settleId.clone());
        m.insert("type".to_string(), type_var.clone());
        m.insert("spot".to_string(), isSpot.clone());
        m.insert("margin".to_string(), Value::Bool(false));
        m.insert("swap".to_string(), isSwap.clone());
        m.insert("future".to_string(), isFuture.clone());
        m.insert("option".to_string(), Value::Bool(false));
        m.insert("active".to_string(), Value::Null);
        m.insert("contract".to_string(), isContract.clone());
        m.insert("linear".to_string(), ternary(is_true(&isSwap), Value::Bool(true), Value::Null));
        m.insert("inverse".to_string(), ternary(is_true(&isSwap), Value::Bool(false), Value::Null));
        m.insert("contractSize".to_string(), self.parse_number(Value::Str("1".to_string()), &[]));
        m.insert("expiry".to_string(), Value::Null);
        m.insert("expiryDatetime".to_string(), Value::Null);
        m.insert("strike".to_string(), Value::Null);
        m.insert("optionType".to_string(), Value::Null);
        m.insert("precision".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("amount".to_string(), self.safe_number_k(market.clone(), "min_size", &[]));
        m.insert("price".to_string(), self.safe_number_k(market.clone(), "tick_size", &[]));
        m.insert("base".to_string(), self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "base_decimals", &[])]), &[]));
        m.insert("quote".to_string(), self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "quote_decimals", &[])]), &[]));
    m
}));
        m.insert("limits".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("leverage".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("amount".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(market.clone(), "min_size", &[]));
        m.insert("max".to_string(), self.safe_number_k(market.clone(), "max_position_size", &[]));
    m
}));
        m.insert("price".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("cost".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(market.clone(), "min_notional", &[]));
        m.insert("max".to_string(), Value::Null);
    m
}));
    m
}));
        m.insert("created".to_string(), self.safe_integer_product(market.clone(), Value::Str("create_time".to_string()), Value::Float(0.000001), &[]));
        m.insert("info".to_string(), market.clone());
    m
});

    Value::Null
}

